# Data models module: Core data structures

@abstract
class DataSource:
    """Abstract base for all data sources"""
    source_id: str
    is_active: bool

    def __init__(self, id: str):
        self.source_id = id
        self.is_active = True

    @abstract
    def fetch_data(self) -> str:
        ...

    def get_status(self) -> str:
        return f"Source {self.source_id} active: {self.is_active}"


class Record:
    """Simple data record"""
    key: str
    value: int
    timestamp: str

    def __init__(self, k: str, v: int, ts: str):
        self.key = k
        self.value = v
        self.timestamp = ts

    def get_summary(self) -> str:
        return f"{self.key}={self.value} at {self.timestamp}"

