# Processors module: Implements data processing logic
from data_models import DataSource, Record

class DatabaseSource(DataSource):
    """Concrete implementation of DataSource"""
    connection_string: str

    def __init__(self, id: str, conn: str):
        super().__init__(id)
        self.connection_string = conn

    @override
    def fetch_data(self) -> str:
        return f"Data from DB: {self.connection_string}"


class FileSource(DataSource):
    """File-based data source"""
    file_path: str

    def __init__(self, id: str, path: str):
        super().__init__(id)
        self.file_path = path

    @override
    def fetch_data(self) -> str:
        return f"Data from file: {self.file_path}"


class RecordProcessor:
    """Processes records from various sources"""
    source: DataSource
    processed_count: int

    def __init__(self, src: DataSource):
        self.source = src
        self.processed_count = 0

    def process(self, record: Record) -> str:
        self.processed_count += 1
        data: str = self.source.fetch_data()
        summary: str = record.get_summary()
        return f"[{self.processed_count}] {data} | {summary}"
